(function($){"use strict";$.fn.preventTextOrphans=function(options){var settings=$.extend({minimum:2,wrapperClass:"text-nowrap"},options);return this.each(function(){var $element=$(this);if($element.hasClass("disable-pto")){return}$element.data("preventTextOrphans-settings",{minimum:settings.minimum,wrapperClass:settings.wrapperClass});$element.addClass("preventTextOrphans-initialized");applyTextOrphanPrevention($element,settings.minimum,settings.wrapperClass)});function applyTextOrphanPrevention($ptoElements,minimum,wrapperClass){$ptoElements.each(function(){const $element=$(this);const $children=$element.children("p, div");if($children.length>0){$children.each(function(){processElement($(this),minimum,wrapperClass)})}else{processElement($element,minimum,wrapperClass)}})}function processElement($element,minimum,wrapperClass){const element=$element[0];const plainText=element.textContent.trim();const words=plainText.split(/\s+/).filter(w=>w.length>0);if(words.length<=minimum){return}const originalHtml=$element.html();const originalHeight=element.offsetHeight;const wordsToWrap=minimum;const targetWordIndex=words.length-wordsToWrap;const wordsBeforeWrap=words.slice(0,targetWordIndex);const textBeforeWrap=wordsBeforeWrap.join(' ');const htmlContent=element.innerHTML;let textIndex=0;let htmlIndex=0;let wrapStartPos=-1;while(htmlIndex<htmlContent.length&&textIndex<textBeforeWrap.length){if(htmlContent[htmlIndex]==='<'){while(htmlIndex<htmlContent.length&&htmlContent[htmlIndex]!=='>'){htmlIndex+=1}htmlIndex+=1;}else if(htmlContent[htmlIndex]==='&'){const entityStart=htmlIndex;while(htmlIndex<htmlContent.length&&htmlContent[htmlIndex]!==';'){htmlIndex+=1}htmlIndex+=1;textIndex+=1}else{if(htmlContent[htmlIndex]===textBeforeWrap[textIndex]){textIndex+=1;htmlIndex+=1}else if(/\s/.test(htmlContent[htmlIndex])&&/\s/.test(textBeforeWrap[textIndex])){while(htmlIndex<htmlContent.length&&/\s/.test(htmlContent[htmlIndex])){htmlIndex+=1}while(textIndex<textBeforeWrap.length&&/\s/.test(textBeforeWrap[textIndex])){textIndex+=1}}else{htmlIndex+=1}}}while(htmlIndex<htmlContent.length&&/\s/.test(htmlContent[htmlIndex])){htmlIndex+=1}wrapStartPos=htmlIndex;if(wrapStartPos===-1||wrapStartPos>=htmlContent.length){return}const beforeWrap=htmlContent.substring(0,wrapStartPos);const afterWrap=htmlContent.substring(wrapStartPos);const wrappedHtml=`${ beforeWrap }<span class="${ wrapperClass }">${ afterWrap }</span>`;$element.html(wrappedHtml);const newHeight=element.offsetHeight;const hasHorizontalOverflow=element.scrollWidth>element.clientWidth;const hasVerticalOverflow=newHeight>originalHeight;if(hasHorizontalOverflow||hasVerticalOverflow){$element.html(originalHtml)}}};$(window).on("resize orientationchange",function(){$('span.text-nowrap').each(function(){const $span=$(this);const html=$span.html();$span.replaceWith(html)});$('.preventTextOrphans-initialized').each(function(){const $el=$(this);const settings=$el.data('preventTextOrphans-settings');if(settings){$el.preventTextOrphans(settings)}})})})(jQuery);